.darma-loader-darma-custom-474 {
   width: calc(5*24px);
   height: 42px;
   display: grid;
   color: var(--loader-color, #6d28d9);
   filter: drop-shadow(30px 25px 0 currentColor) drop-shadow(60px 0 0 currentColor) drop-shadow(120px 0 0 currentColor);
   clip-path: inset(0 100% 0 0);
   animation: darma-loader-darma-custom-474-l14 2s infinite steps(7);
}
.darma-loader-darma-custom-474:before, .darma-loader-darma-custom-474:after  {
  content: "";
   width: 24px;
   grid-area: 1/1;
   height: 9px;
   background: radial-gradient(farthest-side,currentColor 90%,#0000) left/10px 9px, conic-gradient(from -106deg at right,#0000, currentColor 2deg 29deg,#0000 33deg) right/17px 11px;
   background-repeat: no-repeat;
   transform: rotate(7deg);
   transform-origin: 5px 50%;
}
.darma-loader-darma-custom-474:after  {
  margin-top: 12px;
   transform: rotate(-7deg);
}
@keyframes darma-loader-darma-custom-474-l14  {
  100% {clip-path: inset(0 -30px 0 0)}
}

